/// Titan Blueprint MCP Server — Model Context Protocol server for AI assistants.
///
/// Exposes Blueprint data (Terrain, Stratagems, AI prompts) to AI assistants
/// like GitHub Copilot and Claude via the MCP (Model Context Protocol).
///
/// The server reads from `.titan/blueprint.json` (generated by
/// `export_blueprint` or auto-exported by ColossusPlugin) and exposes
/// the data as MCP tools that AI assistants can call.
///
/// ## Usage
///
/// Add to your VS Code settings (`.vscode/settings.json`):
///
/// ```json
/// {
///   "github.copilot.chat.mcpServers": {
///     "titan-blueprint": {
///       "command": "dart",
///       "args": [
///         "run",
///         "titan_colossus:blueprint_mcp_server"
///       ],
///       "cwd": "${workspaceFolder}/packages/titan_colossus"
///     }
///   }
/// }
/// ```
///
/// ## Available Tools
///
/// ### Read-only (static data)
/// - `get_terrain` — Returns the app's navigation graph (screens + transitions)
/// - `get_stratagems` — Returns auto-generated edge-case test plans
/// - `get_ai_prompt` — Returns a complete AI-ready testing context document
/// - `get_dead_ends` — Returns screens with no outgoing transitions
/// - `get_unreliable_routes` — Returns transitions with low reliability
/// - `get_route_patterns` — Returns all known route patterns
///
/// ### AI-driven testing (generate + execute)
/// - `generate_gauntlet` — Generate edge-case tests for a specific route
/// - `get_campaign_template` — Get the Campaign JSON schema for AI to fill
/// - `save_campaign` — Save a generated Campaign JSON to disk for execution
/// - `get_debrief` — Get debrief report from previous campaign results
/// - `get_full_context` — Everything in one call for AI test planning
///
/// ### Live Relay (connects to running app)
/// - `execute_campaign` — Execute Campaign JSON on the running app (zero
///   human interaction)
/// - `relay_status` — Check if the Relay bridge is running
/// - `relay_terrain` — Get live Terrain from the running app
/// - `get_performance` — Get live performance report (Pulse, Stride,
///   Vessel, Echo metrics and health verdict)
/// - `generate_auth_stratagem` — Auto-generate authStratagem from the
///   current screen (detects text fields and login buttons)
/// - `generate_campaign` — Auto-generate a complete Campaign JSON from
///   the live app's current screen
/// - `audit_screen` — Automatically detect data-binding bugs via a
///   sign-out/re-login cycle with a unique probe value
library;

import 'dart:async';
import 'dart:convert';
import 'dart:io';

import 'package:titan_colossus/src/testing/auth_stratagem_generator.dart';
import 'package:titan_colossus/src/testing/screen_auditor.dart';
import 'package:titan_colossus/src/testing/scry.dart';

/// MCP Server for Titan Blueprint data.
///
/// Implements the Model Context Protocol (MCP) over stdio, exposing
/// Blueprint data as tools that AI assistants can invoke.
Future<void> main(List<String> args) async {
  // Ensure stdout handles UTF-8 (em-dash etc. in generated content)
  stdout.encoding = utf8;

  final server = _BlueprintMcpServer();

  // Support CLI arguments for configuration
  for (var i = 0; i < args.length - 1; i++) {
    switch (args[i]) {
      case '--blueprint-path':
        server._blueprintPath = args[i + 1];
      case '--relay-host':
        server._relayHost = args[i + 1];
      case '--relay-port':
        server._relayPort = int.parse(args[i + 1]);
      case '--relay-token':
        server._relayAuthToken = args[i + 1];
    }
  }

  await server.run();
}

class _BlueprintMcpServer {
  String _blueprintPath = '.titan/blueprint.json';
  Map<String, dynamic>? _cachedBlueprint;
  DateTime? _lastModified;
  String _relayHost = '127.0.0.1';
  int _relayPort = 8642;
  String? _relayAuthToken;

  Future<void> run() async {
    // Read JSON-RPC messages from stdin, write responses to stdout
    final lines = stdin.transform(utf8.decoder).transform(const LineSplitter());

    // Support CLI args: --relay-host, --relay-port, --relay-token
    // (parsed in main() and set before run())

    await for (final line in lines) {
      if (line.trim().isEmpty) continue;

      try {
        final request = jsonDecode(line) as Map<String, dynamic>;
        final response = await _handleRequest(request);
        if (response != null) {
          stdout.writeln(jsonEncode(response));
        }
      } catch (e) {
        final errorResponse = {
          'jsonrpc': '2.0',
          'error': {'code': -32700, 'message': 'Parse error: $e'},
          'id': null,
        };
        stdout.writeln(jsonEncode(errorResponse));
      }
    }
  }

  Future<Map<String, dynamic>?> _handleRequest(
    Map<String, dynamic> request,
  ) async {
    final method = request['method'] as String?;
    final id = request['id'];

    switch (method) {
      case 'initialize':
        return _handleInitialize(id, request);
      case 'initialized':
        return null; // Notification, no response needed
      case 'tools/list':
        return _handleToolsList(id);
      case 'tools/call':
        return _handleToolsCall(id, request);
      case 'shutdown':
        return {'jsonrpc': '2.0', 'result': null, 'id': id};
      default:
        return {
          'jsonrpc': '2.0',
          'error': {'code': -32601, 'message': 'Method not found: $method'},
          'id': id,
        };
    }
  }

  Map<String, dynamic> _handleInitialize(
    dynamic id,
    Map<String, dynamic> request,
  ) {
    // Check for custom blueprint path in initialization options
    final params = request['params'] as Map<String, dynamic>?;
    final initOptions =
        params?['initializationOptions'] as Map<String, dynamic>?;
    if (initOptions != null && initOptions['blueprintPath'] is String) {
      _blueprintPath = initOptions['blueprintPath'] as String;
    }

    return {
      'jsonrpc': '2.0',
      'result': {
        'protocolVersion': '2024-11-05',
        'capabilities': {
          'tools': {'listChanged': false},
        },
        'serverInfo': {'name': 'titan-blueprint', 'version': '1.0.0'},
      },
      'id': id,
    };
  }

