                'Also includes the full current screen observation '
                'with spatial layout, landmarks, scroll info, '
                'element groups, reachability, overlay content, '
                'toggle summary, and layout pattern.',
            'inputSchema': {'type': 'object', 'properties': {}},
          },
        ],
      },
      'id': id,
    };
  }

  Future<Map<String, dynamic>> _handleToolsCall(
    dynamic id,
    Map<String, dynamic> request,
  ) async {
    final params = request['params'] as Map<String, dynamic>?;
    final toolName = params?['name'] as String?;
    final toolArgs = params?['arguments'] as Map<String, dynamic>? ?? const {};

    // Relay-based tools don't need the static blueprint file.
    // Handle them before the blueprint load so they work even
    // when .titan/blueprint.json doesn't exist.
    const relayOnlyTools = {
      'execute_campaign',
      'relay_status',
      'relay_terrain',
      'get_performance',
      'get_frame_history',
      'get_page_loads',
      'get_memory_snapshot',
      'get_alerts',
      'list_sessions',
      'get_recording_status',
      'get_framework_errors',
      'generate_auth_stratagem',
      'generate_campaign',
      'audit_screen',
      'scry',
      'scry_act',
    };

    if (relayOnlyTools.contains(toolName)) {
      final result = switch (toolName) {
        'execute_campaign' => await _executeCampaign(toolArgs),
        'relay_status' => await _relayStatus(),
        'relay_terrain' => await _relayTerrain(),
        'get_performance' => await _getPerformance(),
        'get_frame_history' => await _getFrameHistory(),
        'get_page_loads' => await _getPageLoads(),
        'get_memory_snapshot' => await _getMemorySnapshot(),
        'get_alerts' => await _getAlerts(),
        'list_sessions' => await _listSessions(),
        'get_recording_status' => await _getRecordingStatus(),
        'get_framework_errors' => await _getFrameworkErrors(),
        'generate_auth_stratagem' => await _generateAuthStratagem(toolArgs),
        'generate_campaign' => await _generateCampaign(toolArgs),
        'audit_screen' => await _auditScreen(toolArgs),
        'scry' => await _scry(),
        'scry_act' => await _scryAct(toolArgs),
        'scry_diff' => await _scryDiff(),
        _ => 'Unknown tool: $toolName',
      };

      return {
        'jsonrpc': '2.0',
        'result': {
          'content': [
            {'type': 'text', 'text': result},
          ],
        },
        'id': id,
      };
    }

    // Load/refresh Blueprint data for file-based tools.
    final blueprint = await _loadBlueprint();
    if (blueprint == null) {
      return {
        'jsonrpc': '2.0',
        'result': {
          'content': [
            {
              'type': 'text',
              'text':
                  'No Blueprint data found at $_blueprintPath. '
                  'Run your app with ColossusPlugin(blueprintExportDirectory: '
                  "'.titan') or execute: "
                  'dart run titan_colossus:export_blueprint',
            },
          ],
          'isError': true,
        },
        'id': id,
      };
    }

    final result = switch (toolName) {
      'get_terrain' => _getTerrain(blueprint, toolArgs),
      'get_stratagems' => _getStratagems(blueprint, toolArgs),
      'get_ai_prompt' => _getAiPrompt(blueprint),
      'get_dead_ends' => _getDeadEnds(blueprint),
      'get_unreliable_routes' => _getUnreliableRoutes(blueprint),
      'get_route_patterns' => _getRoutePatterns(blueprint),
      'generate_gauntlet' => _generateGauntlet(blueprint, toolArgs),
      'get_campaign_template' => _getCampaignTemplate(),
      'save_campaign' => await _saveCampaign(toolArgs),
      'get_debrief' => _getDebrief(blueprint),
      'get_full_context' => _getFullContext(blueprint),
      _ => 'Unknown tool: $toolName',
    };

    return {
      'jsonrpc': '2.0',
      'result': {
        'content': [
          {'type': 'text', 'text': result},
        ],
      },
      'id': id,
    };
  }

  // -----------------------------------------------------------------------
  // Tool implementations
  // -----------------------------------------------------------------------

  String _getTerrain(
    Map<String, dynamic> blueprint,
    Map<String, dynamic> args,
  ) {
    final format = args['format'] as String? ?? 'ai_map';

    return switch (format) {
      'mermaid' => blueprint['mermaid'] as String? ?? 'No Mermaid data',
      'ai_map' => blueprint['aiMap'] as String? ?? 'No AI map data',
      'json' => const JsonEncoder.withIndent(
        '  ',
      ).convert(blueprint['terrain'] ?? {}),
      _ => 'Unknown format: $format. Use json, mermaid, or ai_map.',
    };
  }

  String _getStratagems(
    Map<String, dynamic> blueprint,
    Map<String, dynamic> args,
  ) {
    final route = args['route'] as String?;
    final stratagems = blueprint['stratagems'] as List<dynamic>? ?? [];

    List<dynamic> filtered = stratagems;
    if (route != null) {
      filtered = stratagems.where((s) {
        final startRoute = (s as Map<String, dynamic>)['startRoute'];
        final name = s['name'] as String? ?? '';
        return startRoute == route || name.contains(route);
      }).toList();
    }

    if (filtered.isEmpty) {
      return route != null
          ? 'No Stratagems found for route: $route'
          : 'No Stratagems generated. Ensure sessions have been '
                'recorded and analyzed.';
    }

    final buf = StringBuffer();
    buf.writeln('# Stratagems (${filtered.length})');
    buf.writeln();

    for (final s in filtered) {
      final map = s as Map<String, dynamic>;
      buf.writeln('## ${map['name']}');
      buf.writeln();
      buf.writeln(map['description'] ?? '');
      buf.writeln();
      buf.writeln('**Start route:** `${map['startRoute']}`');
      final tags = map['tags'] as List<dynamic>?;
      if (tags != null && tags.isNotEmpty) {
        buf.writeln('**Tags:** ${tags.join(', ')}');
      }

      final steps = map['steps'] as List<dynamic>?;
      if (steps != null) {
        buf.writeln('**Steps:** ${steps.length}');
        buf.writeln();
        for (var i = 0; i < steps.length; i++) {
          final step = steps[i] as Map<String, dynamic>;
          buf.writeln(
            '${i + 1}. ${step['description'] ?? step['action'] ?? 'Step ${i + 1}'}',
          );
        }
      }
      buf.writeln();
    }

    return buf.toString();
  }

  String _getAiPrompt(Map<String, dynamic> blueprint) {
    // If we have a pre-generated AI prompt on disk, try loading it
    final promptFile = File(_blueprintPath.replaceAll('.json', '-prompt.md'));
    if (promptFile.existsSync()) {
      return promptFile.readAsStringSync();
    }

    // Fall back to constructing from Blueprint data
    final buf = StringBuffer();
    buf.writeln('# App Blueprint — AI Test Generation Context');
    buf.writeln();
    buf.writeln('Exported: ${blueprint['exportedAt'] ?? 'unknown'}');
    buf.writeln();

    // AI Map
    final aiMap = blueprint['aiMap'] as String?;
    if (aiMap != null) {
      buf.writeln('## Navigation Map');
      buf.writeln();
      buf.writeln(aiMap);
      buf.writeln();
    }

    // Mermaid
    final mermaid = blueprint['mermaid'] as String?;
    if (mermaid != null) {
      buf.writeln('## Navigation Diagram');
      buf.writeln();
      buf.writeln('```mermaid');
      buf.writeln(mermaid);
      buf.writeln('```');
      buf.writeln();
    }

    // Stratagems summary
    final stratagems = blueprint['stratagems'] as List<dynamic>?;
    if (stratagems != null && stratagems.isNotEmpty) {
      buf.writeln('## Test Scenarios (${stratagems.length})');
      buf.writeln();
      for (final s in stratagems) {
        final map = s as Map<String, dynamic>;
        buf.writeln('- **${map['name']}**: ${map['description'] ?? ''}');
      }
      buf.writeln();
    }

    // Lineage
    final lineage = blueprint['lineage'] as Map<String, dynamic>?;
    if (lineage != null) {
      buf.writeln('## Route Patterns');
      buf.writeln();
      final patterns = lineage['patterns'] as List<dynamic>?;
      if (patterns != null) {
        for (final p in patterns) {
          buf.writeln('- `$p`');
        }
      }
      buf.writeln();
    }

    return buf.toString();
  }

  String _getDeadEnds(Map<String, dynamic> blueprint) {
    final terrain = blueprint['terrain'] as Map<String, dynamic>?;
    if (terrain == null) return 'No terrain data available.';

    final outposts = terrain['outposts'] as Map<String, dynamic>?;
    if (outposts == null || outposts.isEmpty) return 'No screens discovered.';

    final deadEnds = <Map<String, dynamic>>[];
    for (final entry in outposts.entries) {
      final outpost = entry.value as Map<String, dynamic>;
      final exits = outpost['exits'] as List<dynamic>?;
      if (exits == null || exits.isEmpty) {
        deadEnds.add({'route': entry.key, ...outpost});
      }
    }

    if (deadEnds.isEmpty) return 'No dead ends found — all screens have exits.';

    final buf = StringBuffer();
    buf.writeln('# Dead Ends (${deadEnds.length})');
    buf.writeln();
    for (final de in deadEnds) {
      buf.writeln(
        '- `${de['routePattern'] ?? de['route']}` — '
        '${de['observationCount'] ?? 0} visits',
      );
    }
    return buf.toString();
  }

  String _getUnreliableRoutes(Map<String, dynamic> blueprint) {
    final terrain = blueprint['terrain'] as Map<String, dynamic>?;
    if (terrain == null) return 'No terrain data available.';

    final outposts = terrain['outposts'] as Map<String, dynamic>?;
    if (outposts == null) return 'No outpost data available.';

    final unreliable = <Map<String, dynamic>>[];
    for (final entry in outposts.entries) {
      final outpost = entry.value as Map<String, dynamic>;
      final exits = outpost['exits'] as List<dynamic>? ?? [];
      for (final exit in exits) {
        final march = exit as Map<String, dynamic>;
        final observations = march['observationCount'] as int? ?? 0;
        if (observations < 2) {
          unreliable.add(march);
        }
      }
    }

    if (unreliable.isEmpty) {
      return 'No unreliable routes found — all transitions have adequate '
          'observations.';
    }

    final buf = StringBuffer();
    buf.writeln('# Unreliable Routes (${unreliable.length})');
    buf.writeln();
    for (final m in unreliable) {
      buf.writeln(
        '- `${m['fromRoute']}` → `${m['toRoute']}` — '
        '${m['observationCount']} observations, '
        'trigger: ${m['trigger'] ?? 'unknown'}',
      );
    }
    return buf.toString();
  }

  String _getRoutePatterns(Map<String, dynamic> blueprint) {
    final lineage = blueprint['lineage'] as Map<String, dynamic>?;
    if (lineage == null) return 'No lineage data available.';

    final patterns = lineage['patterns'] as List<dynamic>? ?? [];
    if (patterns.isEmpty) return 'No route patterns registered.';

    final buf = StringBuffer();
    buf.writeln('# Route Patterns (${patterns.length})');
    buf.writeln();
    for (final p in patterns) {
      buf.writeln('- `$p`');
    }
    return buf.toString();
  }

  // -----------------------------------------------------------------------
  // AI-driven testing tools
  // -----------------------------------------------------------------------

  String _generateGauntlet(
    Map<String, dynamic> blueprint,
    Map<String, dynamic> args,
  ) {
    final route = args['route'] as String?;
    if (route == null || route.isEmpty) {
      return 'Error: "route" parameter is required. '
          'Provide a route pattern like /login or /quest/:id.';
    }

    final intensity = args['intensity'] as String? ?? 'standard';

    // Find the outpost in terrain data
    final terrain = blueprint['terrain'] as Map<String, dynamic>?;
    if (terrain == null) return 'No terrain data available.';

    final outposts = terrain['outposts'] as Map<String, dynamic>?;
    if (outposts == null || outposts.isEmpty) return 'No screens discovered.';

    final outpost = outposts[route] as Map<String, dynamic>?;
    if (outpost == null) {
      final available = outposts.keys.take(10).join(', ');
      return 'No screen found for route "$route". '
          'Available routes: $available';
    }

    // Find pre-generated stratagems for this route
    final stratagems = blueprint['stratagems'] as List<dynamic>? ?? [];
    final matching = stratagems.where((s) {
      final map = s as Map<String, dynamic>;
      return map['startRoute'] == route;
    }).toList();

    if (matching.isEmpty) {
      return 'No Gauntlet patterns found for "$route". '
          'Re-export the blueprint with: '
          'dart run titan_colossus:export_blueprint --intensity $intensity';
    }

    final buf = StringBuffer();
    buf.writeln('# Gauntlet Patterns for `$route` (${matching.length})');
    buf.writeln();
    buf.writeln('Intensity: $intensity');
    buf.writeln();

    for (final s in matching) {
      final map = s as Map<String, dynamic>;
      buf.writeln('## ${map['name']}');
      buf.writeln();
      buf.writeln(map['description'] ?? '');
      buf.writeln();

      final tags = map['tags'] as List<dynamic>?;
      if (tags != null && tags.isNotEmpty) {
        buf.writeln('**Tags:** ${tags.join(', ')}');
      }

      final steps = map['steps'] as List<dynamic>?;
      if (steps != null) {
        buf.writeln('**Steps:**');
        for (var i = 0; i < steps.length; i++) {
          final step = steps[i] as Map<String, dynamic>;
          buf.writeln(
            '${i + 1}. [${step['action']}] '
            '${step['description'] ?? ''}',
          );
        }
      }
      buf.writeln();
    }

    buf.writeln('---');
    buf.writeln();
    buf.writeln('### Raw JSON (for Campaign use)');
    buf.writeln();
    buf.writeln('```json');
    buf.writeln(const JsonEncoder.withIndent('  ').convert(matching));
    buf.writeln('```');

    return buf.toString();
  }

  String _getCampaignTemplate() {
    final template = {
      r'$schema': 'titan://campaign/v1',
      'name': '<campaign_name>',
      'description': '<description>',
      'tags': ['<tag1>', '<tag2>'],
      'sharedTestData': {'heroName': '<test_hero_name>'},
      'includeGauntlet': false,
      'gauntletIntensity': 'standard',
      'failurePolicy': 'skipDependents',
      'timeout': 300000,
      'authStratagem': {
        'name': '<auth_stratagem_name>',
        'startRoute': '/login',
        'steps': [
          {
            'id': 1,
            'action': 'enterText',
            'target': {'label': '<text_field_label>'},
            'value': '<text_to_enter>',
          },
          {
            'id': 2,
            'action': 'tap',
            'target': {'label': '<login_button_label>'},
          },
        ],
      },
      'entries': [
        {
          'stratagem': {
            'name': '<stratagem_name>',
            'description': '<what_this_tests>',
            'startRoute': '/',
            'tags': ['<tag>'],
            'steps': [
              {
                'id': 1,
                'action': 'tap',
                'description': '<step_description>',
                'target': {'label': '<widget_label>', 'type': '<widget_type>'},
              },
              {
                'id': 2,
                'action': 'waitForElement',
                'target': {'label': '<expected_element>'},
              },
              {
                'id': 3,
                'action': 'enterText',
                'target': {'label': '<field_label>'},
                'value': '<text_to_type>',
              },
            ],
          },
          'dependsOn': <String>[],
        },
      ],
    };

    final buf = StringBuffer();
    buf.writeln('# Campaign Template');
    buf.writeln();
    buf.writeln(
      'A Campaign is an ordered suite of Stratagems (test plans) '
      'with dependency resolution.',
    );
    buf.writeln();
    buf.writeln('## Schema Requirements');
    buf.writeln();
    buf.writeln('### Campaign (top-level)');
    buf.writeln('- `name` (String, REQUIRED) — campaign identifier');
    buf.writeln(
      '- `entries` (List, REQUIRED) — array of CampaignEntry objects',
    );
    buf.writeln('- `authStratagem` (Stratagem, optional) — auto-login config');
    buf.writeln(
      '- `description`, `tags`, `sharedTestData`, '
      '`failurePolicy`, `timeout` — optional',
    );
    buf.writeln();
    buf.writeln('### Stratagem (inside each entry)');
    buf.writeln('- `name` (String, REQUIRED) — stratagem identifier');
    buf.writeln(
      '- `startRoute` (String, REQUIRED) — '
      'route to navigate to before steps. Use "/" for root.',
    );
    buf.writeln('- `steps` (List, REQUIRED) — ordered list of steps');
    buf.writeln();
    buf.writeln('### StratagemStep');
    buf.writeln(
      '- `id` (int, REQUIRED) — sequential integer starting from 1. '
      'NOT a string.',
    );
    buf.writeln(
      '- `action` (String, REQUIRED) — '
      'one of the available actions listed below',
    );
    buf.writeln(
      '- `target` (object, optional) — '
      'identifies UI element by `label`, `type`, `key`, `index`',
    );
    buf.writeln('- `value` (String, optional) — text for enterText actions');
    buf.writeln();
    buf.writeln('### StratagemTarget (finding elements)');
    buf.writeln('- `label` (String) — widget label text (most common)');
    buf.writeln('- `type` (String) — widget type name');
    buf.writeln('- `key` (String) — widget Key value');
    buf.writeln('- `index` (int) — nth matching element (0-based)');
    buf.writeln('- `semanticRole` (String) — e.g. "button"');
    buf.writeln('- `ancestor` (String) — ancestor widget type filter');
    buf.writeln();
    buf.writeln('## Available Actions');
    buf.writeln();
    buf.writeln('**Interactions:** `tap`, `longPress`, `doubleTap`');
    buf.writeln('**Text:** `enterText`, `clearText`, `submitField`');
    buf.writeln(
      '**Scroll/Swipe:** `scroll`, `scrollUntilVisible`, `swipe`, `drag`',
    );
    buf.writeln(
      '**Toggle/Select:** `toggleSwitch`, `toggleCheckbox`, '
      '`selectRadio`, `adjustSlider`, `selectDropdown`, '
      '`selectDate`, `selectSegment`',
    );
    buf.writeln('**Navigation:** `navigate`, `back`');
    buf.writeln('**Waiting:** `wait`, `waitForElement`, `waitForElementGone`');
    buf.writeln('**Verification:** `verify`');
    buf.writeln('**Keyboard:** `dismissKeyboard`, `pressKey`');
    buf.writeln();
    buf.writeln('## Failure Policies');
    buf.writeln();
    buf.writeln('- `skipDependents` — skip entries that depend on a failure');
    buf.writeln('- `abortOnFirst` — stop the entire Campaign on first failure');
    buf.writeln('- `continueAll` — execute everything regardless of failures');
    buf.writeln();
    buf.writeln('## Common Mistakes to Avoid');
    buf.writeln();
    buf.writeln('1. Step `id` must be an **int** (1, 2, 3), NOT a string');
    buf.writeln(
      '2. `startRoute` is REQUIRED on every Stratagem '
      '(including authStratagem)',
    );
    buf.writeln(
      '3. Use `entries` array (each with nested `stratagem` '
      'object), NOT top-level `stratagems`',
    );
    buf.writeln('4. Target field is `label`, NOT `semanticLabel`');
    buf.writeln(
      '5. Use `enterText` for text input, NOT `type` '
      '(which is not a valid action)',
    );
    buf.writeln(
      '6. Use `waitForElement` for assertions, NOT `assert` '
      '(which is not a valid action)',
    );
    buf.writeln();
    buf.writeln('## Template JSON');
    buf.writeln();
    buf.writeln('```json');
    buf.writeln(const JsonEncoder.withIndent('  ').convert(template));
    buf.writeln('```');
    buf.writeln();
    buf.writeln('## Workflow');
    buf.writeln();
    buf.writeln(
      '1. Call `generate_auth_stratagem` to auto-detect login fields',
    );
    buf.writeln(
      '2. Call `get_full_context` to understand the app\'s navigation',
    );
    buf.writeln(
      '3. Generate Campaign JSON using this template with '
      'correct field types',
    );
    buf.writeln(
      '4. Call `execute_campaign` to run via Relay, or '
      '`save_campaign` to save to disk',
    );

    return buf.toString();
  }

  Future<String> _saveCampaign(Map<String, dynamic> args) async {
    final campaign = args['campaign'] as Map<String, dynamic>?;
    if (campaign == null) {
      return 'Error: "campaign" parameter is required. '
          'Provide a Campaign JSON object.';
    }

    try {
      // Validate basic structure
      if (campaign['name'] == null) {
        return 'Error: Campaign must have a "name" field.';
      }
      if (campaign['entries'] is! List) {
        return 'Error: Campaign must have an "entries" array.';
      }

      final dir = Directory(
        _blueprintPath.contains('/')
            ? _blueprintPath.substring(0, _blueprintPath.lastIndexOf('/'))
            : '.titan',
      );
      if (!dir.existsSync()) {
        await dir.create(recursive: true);
      }

      final file = File('${dir.path}/campaign.json');
      final json = const JsonEncoder.withIndent('  ').convert(campaign);
      await file.writeAsString(json);

      return 'Campaign saved to ${file.absolute.path}\n\n'
          'The running app can load this with:\n'
          '```dart\n'
          "final json = jsonDecode(File('.titan/campaign.json')"
          '.readAsStringSync());\n'
          'final result = await Colossus.instance'
          '.executeCampaignJson(json);\n'
          '```\n\n'
          'Or paste the JSON into the Lens Blueprint tab → Campaign view.';
    } catch (e) {
      return 'Error saving Campaign: $e';
    }
  }

  String _getDebrief(Map<String, dynamic> blueprint) {
    // Check for debrief data in the Blueprint
    final debrief = blueprint['debrief'] as Map<String, dynamic>?;

    if (debrief == null) {
      // Check for verdicts without debrief
      final verdicts = blueprint['verdicts'] as List<dynamic>?;
      if (verdicts == null || verdicts.isEmpty) {
        return 'No test results available yet. '
            'Execute a Campaign first, then re-export the Blueprint '
            'with verdicts included.';
      }
      return 'Verdicts exist but no debrief analysis. '
          'Re-export the Blueprint to generate a debrief.';
    }

    final buf = StringBuffer();
    buf.writeln('# Debrief Report');
    buf.writeln();

    final total = debrief['totalVerdicts'] as int? ?? 0;
    final passed = debrief['passedVerdicts'] as int? ?? 0;
    final failed = total - passed;
    final passRate = total > 0 ? (passed / total * 100) : 0.0;

    buf.writeln('## Summary');
    buf.writeln();
    buf.writeln('- **Total:** $total tests');
    buf.writeln('- **Passed:** $passed');
    buf.writeln('- **Failed:** $failed');
    buf.writeln('- **Pass rate:** ${passRate.toStringAsFixed(1)}%');
    buf.writeln();

    final insights = debrief['insights'] as List<dynamic>? ?? [];
    if (insights.isNotEmpty) {
      buf.writeln('## Insights (${insights.length})');
      buf.writeln();
      for (final insight in insights) {
        final map = insight as Map<String, dynamic>;
        buf.writeln('### ${map['title'] ?? 'Insight'}');
        buf.writeln();
        buf.writeln(map['description'] ?? '');
        final severity = map['severity'] as String?;
        if (severity != null) {
          buf.writeln('**Severity:** $severity');
        }
        final suggestion = map['suggestion'] as String?;
        if (suggestion != null) {
          buf.writeln('**Suggestion:** $suggestion');
        }
        buf.writeln();
      }
    }

    // Include raw verdicts summary
    final verdicts = blueprint['verdicts'] as List<dynamic>? ?? [];
    final failedVerdicts = verdicts
        .where((v) => (v as Map)['passed'] != true)
        .toList();

    if (failedVerdicts.isNotEmpty) {
      buf.writeln('## Failed Tests');
      buf.writeln();
      for (final v in failedVerdicts) {
        final map = v as Map<String, dynamic>;
        buf.writeln('### ${map['stratagemName'] ?? 'Unknown'}');
        final steps = map['steps'] as List<dynamic>? ?? [];
        final failedSteps = steps.where(
          (s) => (s as Map)['status'] != 'passed',
        );
        for (final step in failedSteps) {
          final s = step as Map<String, dynamic>;
          final failure = s['failure'] as Map<String, dynamic>?;
          buf.writeln(
            '- **${s['description']}**: '
            '${failure?['message'] ?? s['status']}',
          );
        }
        buf.writeln();
      }
    }

    return buf.toString();
  }

  String _getFullContext(Map<String, dynamic> blueprint) {
    final buf = StringBuffer();

    buf.writeln('# Full Blueprint Context for AI Test Planning');
    buf.writeln();
    buf.writeln(
      '> Use this data to generate Campaign JSON. Call '
      '`get_campaign_template` for the schema, then `save_campaign` '
      'to save the generated tests.',
    );
    buf.writeln();

    // 1. Navigation map
    buf.writeln('## 1. Navigation Map');
    buf.writeln();
    final aiMap = blueprint['aiMap'] as String?;
    if (aiMap != null) {
      buf.writeln(aiMap);
    } else {
      buf.writeln('No navigation map available.');
    }
    buf.writeln();

    // 2. Dead ends
    buf.writeln('## 2. Dead Ends');
    buf.writeln();
    buf.writeln(_getDeadEnds(blueprint));
    buf.writeln();

    // 3. Unreliable routes
    buf.writeln('## 3. Unreliable Routes');
    buf.writeln();
    buf.writeln(_getUnreliableRoutes(blueprint));
    buf.writeln();

    // 4. Existing test scenarios
    final stratagems = blueprint['stratagems'] as List<dynamic>? ?? [];
    buf.writeln('## 4. Available Stratagems (${stratagems.length})');
    buf.writeln();
    if (stratagems.isNotEmpty) {
      for (final s in stratagems) {
        final map = s as Map<String, dynamic>;
        buf.writeln(
          '- **${map['name']}** → `${map['startRoute']}` '
          '(${(map['steps'] as List?)?.length ?? 0} steps)',
        );
      }
    } else {
      buf.writeln('No Stratagems generated yet.');
    }
    buf.writeln();

    // 5. Previous results
    final verdicts = blueprint['verdicts'] as List<dynamic>? ?? [];
    if (verdicts.isNotEmpty) {
      final passed = verdicts.where((v) => (v as Map)['passed'] == true);
      buf.writeln('## 5. Previous Results');
      buf.writeln();
      buf.writeln('- Passed: ${passed.length}/${verdicts.length}');

      final debrief = blueprint['debrief'] as Map<String, dynamic>?;
      if (debrief != null) {
        final insights = debrief['insights'] as List<dynamic>? ?? [];
        if (insights.isNotEmpty) {
          buf.writeln();
          buf.writeln('### Key Insights');
          for (final i in insights) {
            final map = i as Map<String, dynamic>;
            buf.writeln('- ${map['title']}: ${map['description']}');
          }
        }
      }
      buf.writeln();
    }

    // 6. Route patterns
    buf.writeln('## 6. Route Patterns');
    buf.writeln();
    buf.writeln(_getRoutePatterns(blueprint));
    buf.writeln();

    // 7. Quick-start instructions
    buf.writeln('## 7. Next Steps');
    buf.writeln();
    buf.writeln(
      '1. Call `get_campaign_template` to see the Campaign JSON schema',
    );
    buf.writeln('2. Generate a Campaign JSON using the terrain data above');
    buf.writeln(
      '3. Use `generate_gauntlet` for edge-case tests on specific routes',
    );
    buf.writeln('4. Call `save_campaign` to save the Campaign for execution');
    buf.writeln(
      '5. Call `execute_campaign` to run the campaign on the live app '
      '(zero human interaction)',
    );
    buf.writeln('6. After execution, call `get_debrief` to analyze results');

    return buf.toString();
  }

  // -----------------------------------------------------------------------
  // Relay — live communication with the running app
  // -----------------------------------------------------------------------

  Uri _relayUri(String path) =>
      Uri.parse('http://$_relayHost:$_relayPort$path');

  Map<String, String> get _relayHeaders => {
    'Content-Type': 'application/json',
    if (_relayAuthToken != null) 'Authorization': 'Bearer $_relayAuthToken',
  };

  /// Execute a Campaign on the running app via the Relay HTTP bridge.
  ///
  /// POST /campaign with the full Campaign JSON body. The Relay runs the
  /// campaign through [Colossus.executeCampaignJson] on the app's main
  /// isolate and returns structured results (pass rate, verdicts, report,
  /// and AI diagnostic).
  ///
  /// Timeout is generous (10 minutes) because campaigns run UI interactions
  /// and each step can take hundreds of milliseconds.
  Future<String> _executeCampaign(Map<String, dynamic> args) async {
    final campaign = args['campaign'] as Map<String, dynamic>?;
    if (campaign == null || campaign.isEmpty) {
      return 'Error: campaign parameter is required. '
          'Call get_campaign_template to see the schema.';
    }

    final client = HttpClient();
    try {
      client.connectionTimeout = const Duration(seconds: 10);

      final request = await client.postUrl(_relayUri('/campaign'));
      _relayHeaders.forEach(request.headers.set);
      request.add(utf8.encode(jsonEncode(campaign)));

      final response = await request.close().timeout(
        const Duration(minutes: 10),
        onTimeout: () => throw TimeoutException(
          'Campaign execution timed out after 10 minutes',
        ),
      );

      final body = await response.transform(utf8.decoder).join();

      if (response.statusCode == 200) {
        // Pretty-format the result for AI consumption
        try {
          final result = jsonDecode(body) as Map<String, dynamic>;
          return _formatCampaignResult(result);
        } catch (_) {
          return body;
        }
      } else {
        return 'Relay returned ${response.statusCode}: $body';
      }
    } on SocketException catch (e) {
      return 'Cannot connect to Relay at '
          'http://$_relayHost:$_relayPort — '
          'is the app running with ColossusPlugin(enableRelay: true)?\n'
          'Error: $e';
    } on TimeoutException catch (e) {
      return 'Relay request timed out: $e';
    } finally {
      client.close();
    }
  }

  /// Format campaign execution result for AI readability.
  String _formatCampaignResult(Map<String, dynamic> result) {
    final buf = StringBuffer();

    buf.writeln('# Campaign Execution Results');
    buf.writeln();

    final passRate = result['passRate'];
    if (passRate != null) {
      final pct = (passRate is double)
          ? (passRate * 100).toStringAsFixed(1)
          : passRate.toString();
      buf.writeln('**Pass Rate**: $pct%');
    }

    final report = result['report'] as String?;
    if (report != null && report.isNotEmpty) {
      buf.writeln();
      buf.writeln('## Report');
      buf.writeln(report);
    }

    final diagnostic = result['aiDiagnostic'] as String?;
    if (diagnostic != null && diagnostic.isNotEmpty) {
      buf.writeln();
      buf.writeln('## AI Diagnostic');
      buf.writeln(diagnostic);
    }

    final verdicts = result['verdicts'] as List<dynamic>?;
    if (verdicts != null && verdicts.isNotEmpty) {
      buf.writeln();
      buf.writeln('## Verdicts');
      buf.writeln();

      for (final v in verdicts) {
        final map = v as Map<String, dynamic>;
        final passed = map['passed'] == true;
        final icon = passed ? '\u2705' : '\u274c';
        buf.writeln(
          '$icon **${map['stratagemName'] ?? 'Unknown'}** — '
          '${passed ? 'PASSED' : 'FAILED'}',
        );

        if (!passed) {
          final steps = map['steps'] as List<dynamic>? ?? [];
          for (final step in steps) {
            final s = step as Map<String, dynamic>;
            if (s['status'] != 'passed') {
              final failure = s['failure'] as Map<String, dynamic>?;
              buf.writeln(
                '  - ${s['description']}: '
                '${failure?['message'] ?? s['status']}',
              );
            }
          }
        }
      }
    }

    return buf.toString();
  }

  /// Check whether the Relay HTTP bridge is running in the app.
  Future<String> _relayStatus() async {
    final client = HttpClient();
    try {
      client.connectionTimeout = const Duration(seconds: 5);

      final request = await client.getUrl(_relayUri('/health'));
      _relayHeaders.forEach(request.headers.set);

      final response = await request.close().timeout(
        const Duration(seconds: 5),
      );

      final body = await response.transform(utf8.decoder).join();

      if (response.statusCode == 200) {
        try {
          final data = jsonDecode(body) as Map<String, dynamic>;
          final buf = StringBuffer();
          buf.writeln('Relay is RUNNING');
          buf.writeln('- Server: http://$_relayHost:$_relayPort');
          buf.writeln('- Status: ${data['status'] ?? 'ok'}');
          buf.writeln('- Uptime: ${data['uptime'] ?? 'unknown'}');
          if (data['requestCount'] != null) {
            buf.writeln('- Requests served: ${data['requestCount']}');
          }
          return buf.toString();
        } catch (_) {
          return 'Relay is running at '
              'http://$_relayHost:$_relayPort\n$body';
        }
      } else {
        return 'Relay returned ${response.statusCode}: $body';
      }
    } on SocketException {
      return 'Relay is NOT RUNNING at '
          'http://$_relayHost:$_relayPort\n\n'
          'To start:\n'
          '1. Launch your app with '
          'ColossusPlugin(enableRelay: true)\n'
          '2. Or call Colossus.instance.startRelay()';
    } on TimeoutException {
      return 'Relay at http://$_relayHost:$_relayPort '
          'did not respond (timeout)';
    } finally {
      client.close();
    }
  }

  // -----------------------------------------------------------------------
  // Performance report
  // -----------------------------------------------------------------------

  /// Fetch a live performance Decree from the running app.
  Future<String> _getPerformance() async {
    return _fetchAndFormat('/performance', _formatPerformanceReport);
  }

  /// Format the raw Decree JSON into readable Markdown.
  String _formatPerformanceReport(Map<String, dynamic> data) {
    final buf = StringBuffer();
    final health = (data['health'] as String? ?? 'unknown').toUpperCase();
    final durationSec = data['durationSeconds'] as int? ?? 0;

    buf.writeln('# Performance Report');
    buf.writeln();
    buf.writeln(
      '**Health:** $health | '
      '**Session Duration:** ${durationSec}s',
    );
    buf.writeln();

    // --- Pulse (Frames) ---
    final pulse = data['pulse'] as Map<String, dynamic>? ?? {};
    final fps = pulse['avgFps'] ?? 0;
    final totalFrames = pulse['totalFrames'] ?? 0;
    final jankFrames = pulse['jankFrames'] ?? 0;
    final jankRate = pulse['jankRate'] ?? 0;
    final avgBuildUs = pulse['avgBuildTimeUs'] ?? 0;
    final avgRasterUs = pulse['avgRasterTimeUs'] ?? 0;

    buf.writeln('## Pulse (Frames)');
    buf.writeln();
    buf.writeln('| Metric | Value |');
    buf.writeln('|--------|-------|');
    buf.writeln('| FPS | $fps |');
    buf.writeln('| Total Frames | $totalFrames |');
    buf.writeln('| Jank Frames | $jankFrames |');
    buf.writeln('| Jank Rate | $jankRate% |');
    buf.writeln('| Avg Build Time | $avgBuildUsµs |');
    buf.writeln('| Avg Raster Time | $avgRasterUsµs |');
    buf.writeln();

    // --- Stride (Page Loads) ---
    final stride = data['stride'] as Map<String, dynamic>? ?? {};
    final totalPageLoads = stride['totalPageLoads'] ?? 0;
    final avgPageLoadMs = stride['avgPageLoadMs'] ?? 0;
    final pageLoads = stride['pageLoads'] as List<dynamic>? ?? [];
    final slowest = stride['slowestPageLoad'] as Map<String, dynamic>?;

    buf.writeln('## Stride (Page Loads)');
    buf.writeln();
    buf.writeln('| Metric | Value |');
    buf.writeln('|--------|-------|');
    buf.writeln('| Total | $totalPageLoads |');
    buf.writeln('| Avg Load Time | ${avgPageLoadMs}ms |');
    if (slowest != null) {
      buf.writeln(
        '| Slowest | ${slowest['path']} (${slowest['durationMs'] ?? slowest['duration'] ?? '?'}ms) |',
      );
    }
    buf.writeln();

    if (pageLoads.isNotEmpty) {
      buf.writeln('**Recent Page Loads:**');
      buf.writeln();
      for (final pl in pageLoads.take(10)) {
        final p = pl as Map<String, dynamic>;
        buf.writeln(
          '- ${p['path'] ?? p['name'] ?? '?'}: '
          '${p['durationMs'] ?? p['duration'] ?? '?'}ms',
        );
      }
      buf.writeln();
    }

    // --- Vessel (Memory) ---
    final vessel = data['vessel'] as Map<String, dynamic>? ?? {};
    final pillarCount = vessel['pillarCount'] ?? 0;
    final totalInstances = vessel['totalInstances'] ?? 0;
    final leakSuspects = vessel['leakSuspects'] as List<dynamic>? ?? [];

    buf.writeln('## Vessel (Memory)');
    buf.writeln();
    buf.writeln('| Metric | Value |');
    buf.writeln('|--------|-------|');
    buf.writeln('| Pillar Count | $pillarCount |');
    buf.writeln('| Total DI Instances | $totalInstances |');
    buf.writeln('| Leak Suspects | ${leakSuspects.length} |');
    buf.writeln();

    if (leakSuspects.isNotEmpty) {
      buf.writeln('**Leak Suspects:**');
      buf.writeln();
      for (final s in leakSuspects) {
        final suspect = s as Map<String, dynamic>;
        buf.writeln(
          '- ${suspect['typeName'] ?? '?'} '
          '(age: ${suspect['ageSeconds'] ?? suspect['age'] ?? '?'}s)',
        );
      }
      buf.writeln();
    }

    // --- Echo (Rebuilds) ---
    final echo = data['echo'] as Map<String, dynamic>? ?? {};
    final totalRebuilds = echo['totalRebuilds'] ?? 0;
    final topRebuilders = echo['topRebuilders'] as Map<String, dynamic>? ?? {};

    buf.writeln('## Echo (Rebuilds)');
    buf.writeln();
    buf.writeln('| Metric | Value |');
    buf.writeln('|--------|-------|');
    buf.writeln('| Total Rebuilds | $totalRebuilds |');
    buf.writeln();

    if (topRebuilders.isNotEmpty) {
      buf.writeln('**Top Rebuilders:**');
      buf.writeln();
      for (final entry in topRebuilders.entries) {
        buf.writeln('- **${entry.key}**: ${entry.value} rebuilds');
      }
      buf.writeln();
    }

    return buf.toString();
  }

  // -----------------------------------------------------------------------
  // Frame History (Pulse detail)
  // -----------------------------------------------------------------------

  /// Fetch per-frame timing history from the running app.
  Future<String> _getFrameHistory() async {
    return _fetchAndFormat('/frames', _formatFrameHistory);
  }

  /// Format frame history JSON into Markdown.
  String _formatFrameHistory(Map<String, dynamic> data) {
    final buf = StringBuffer();
    final total = data['totalFrames'] as int? ?? 0;
    final frames = data['frames'] as List<dynamic>? ?? [];

    buf.writeln('# Frame History (Pulse)');
    buf.writeln();
    buf.writeln(
      '**Total Frames Recorded:** $total | '
      '**History Size:** ${frames.length}',
    );
    buf.writeln();

    if (frames.isEmpty) {
      buf.writeln('No frame data captured yet.');
      return buf.toString();
    }

    // Summary stats
    final jankCount = frames.where((f) {
      final m = f as Map<String, dynamic>;
      return m['isJank'] == true;
    }).length;
    final severeCount = frames.where((f) {
      final m = f as Map<String, dynamic>;
      return m['isSevereJank'] == true;
    }).length;

    buf.writeln('| Metric | Value |');
    buf.writeln('|--------|-------|');
    buf.writeln('| Frames in History | ${frames.length} |');
    buf.writeln('| Jank Frames | $jankCount |');
    buf.writeln('| Severe Jank | $severeCount |');
    buf.writeln();

    // Show recent janky frames
    final janky = frames
        .cast<Map<String, dynamic>>()
        .where((f) => f['isJank'] == true)
        .toList();

    if (janky.isNotEmpty) {
      buf.writeln('## Janky Frames (${janky.length})');
      buf.writeln();
      buf.writeln('| Build (µs) | Raster (µs) | Total (µs) | Severe | Time |');
      buf.writeln('|------------|-------------|------------|--------|------|');
      for (final f in janky.take(20)) {
        buf.writeln(
          '| ${f['buildDurationUs']} '
          '| ${f['rasterDurationUs']} '
          '| ${f['totalDurationUs']} '
          '| ${f['isSevereJank'] == true ? 'YES' : 'no'} '
          '| ${f['timestamp'] ?? ''} |',
        );
      }
      if (janky.length > 20) {
        buf.writeln('| ... | ... | ... | ... | ${janky.length - 20} more |');
      }
      buf.writeln();
    }

    // Show last 10 frames
    buf.writeln('## Recent Frames (last 10)');
    buf.writeln();
    buf.writeln('| Build (µs) | Raster (µs) | Total (µs) | Jank |');
    buf.writeln('|------------|-------------|------------|------|');
    for (final f in frames.reversed.take(10)) {
      final m = f as Map<String, dynamic>;
      buf.writeln(
        '| ${m['buildDurationUs']} '
        '| ${m['rasterDurationUs']} '
        '| ${m['totalDurationUs']} '
        '| ${m['isJank'] == true ? 'JANK' : 'ok'} |',
      );
    }
    buf.writeln();

    return buf.toString();
  }

