  /// Format recording status JSON into Markdown.
  String _formatRecordingStatus(Map<String, dynamic> data) {
    final buf = StringBuffer();
    final isRecording = data['isRecording'] as bool? ?? false;
    final isReplaying = data['isReplaying'] as bool? ?? false;
    final eventCount = data['currentEventCount'] as int? ?? 0;
    final elapsedMs = data['elapsedMs'] as int? ?? 0;
    final isPerfRecording = data['isPerfRecording'] as bool? ?? false;
    final hasLastSession = data['hasLastSession'] as bool? ?? false;

    buf.writeln('# Recording Status (Shade)');
    buf.writeln();
    buf.writeln('| Property | Value |');
    buf.writeln('|----------|-------|');
    buf.writeln('| Recording | ${isRecording ? 'ACTIVE' : 'inactive'} |');
    buf.writeln('| Replaying | ${isReplaying ? 'ACTIVE' : 'inactive'} |');
    buf.writeln('| Event Count | $eventCount |');
    buf.writeln('| Elapsed | ${(elapsedMs / 1000).toStringAsFixed(1)}s |');
    buf.writeln(
      '| Perf Recording | '
      '${isPerfRecording ? 'ACTIVE' : 'inactive'} |',
    );
    buf.writeln(
      '| Last Session | '
      '${hasLastSession ? 'available' : 'none'} |',
    );
    buf.writeln();

    return buf.toString();
  }

  /// Format framework errors JSON into Markdown.
  String _formatFrameworkErrors(Map<String, dynamic> data) {
    final buf = StringBuffer();
    final errors = data['errors'] as List<dynamic>? ?? [];
    final total = data['total'] as int? ?? 0;
    final byCategory = data['byCategory'] as Map<String, dynamic>? ?? {};

    buf.writeln('# Framework Errors');
    buf.writeln();

    if (errors.isEmpty) {
      buf.writeln('No framework errors captured.');
      buf.writeln();
      return buf.toString();
    }

    // Category summary
    buf.writeln('## Summary ($total total)');
    buf.writeln();
    buf.writeln('| Category | Count |');
    buf.writeln('|----------|-------|');
    for (final entry in byCategory.entries) {
      final count = entry.value as int? ?? 0;
      if (count > 0) {
        buf.writeln('| ${entry.key} | $count |');
      }
    }
    buf.writeln();

    // Recent errors (last 20)
    final recent = errors.length > 20
        ? errors.sublist(errors.length - 20)
        : errors;
    buf.writeln('## Recent Errors (${recent.length} shown)');
    buf.writeln();
    buf.writeln('| # | Category | Library | Message | Time |');
    buf.writeln('|---|----------|---------|---------|------|');
    for (var i = 0; i < recent.length; i++) {
      final e = recent[i] as Map<String, dynamic>;
      final cat = e['category'] as String? ?? 'other';
      final msg = (e['message'] as String? ?? '')
          .replaceAll('|', '\\|')
          .replaceAll('\n', ' ');
      final truncMsg = msg.length > 80 ? '${msg.substring(0, 80)}...' : msg;
      final lib = e['library'] as String? ?? '-';
      final ts = e['timestamp'] as String? ?? '';
      final time = ts.length >= 19 ? ts.substring(11, 19) : ts;
      buf.writeln('| ${i + 1} | $cat | $lib | $truncMsg | $time |');
    }
    buf.writeln();

    return buf.toString();
  }

  // -----------------------------------------------------------------------
  // Shared Relay fetch helper
  // -----------------------------------------------------------------------

  /// Fetch JSON from a Relay endpoint and format with the given formatter.
  Future<String> _fetchAndFormat(
    String path,
    String Function(Map<String, dynamic>) formatter,
  ) async {
    final client = HttpClient();
    try {
      client.connectionTimeout = const Duration(seconds: 5);

      final request = await client.getUrl(_relayUri(path));
      _relayHeaders.forEach(request.headers.set);

      final response = await request.close().timeout(
        const Duration(seconds: 5),
      );

      final body = await response.transform(utf8.decoder).join();

      if (response.statusCode != 200) {
        return 'Relay returned ${response.statusCode}: $body';
      }

      final data = jsonDecode(body) as Map<String, dynamic>;
      return formatter(data);
    } on SocketException {
      return '# ${path.substring(1).replaceFirst(path[1], path[1].toUpperCase())} Unavailable\n\n'
          'Relay is not running at '
          'http://$_relayHost:$_relayPort\n\n'
          'Start your app with `ColossusPlugin(enableRelay: true)` '
          'first.';
    } on TimeoutException {
      return '# ${path.substring(1)} Unavailable\n\n'
          'Relay did not respond (timeout).';
    } finally {
      client.close();
    }
  }

  // -----------------------------------------------------------------------
  // Auth Stratagem auto-generation
  // -----------------------------------------------------------------------

  /// Instance of the generator for glyph analysis.
  static const _authGenerator = AuthStratagemGenerator();

  /// Auto-generate an `authStratagem` from the current screen.
  ///
  /// Connects to the Relay `/blueprint` endpoint, captures the
  /// current Tableau, and delegates to [AuthStratagemGenerator]
  /// for glyph analysis. Returns formatted Markdown with the
  /// generated JSON.
  Future<String> _generateAuthStratagem(Map<String, dynamic> args) async {
    final defaultValue = args['defaultValue'] as String? ?? '<fill_in_value>';

    final client = HttpClient();
    try {
      client.connectionTimeout = const Duration(seconds: 5);

      final request = await client.getUrl(_relayUri('/blueprint'));
      _relayHeaders.forEach(request.headers.set);

      final response = await request.close().timeout(
        const Duration(seconds: 5),
      );

      final body = await response.transform(utf8.decoder).join();

      if (response.statusCode != 200) {
        return 'Relay returned ${response.statusCode}: $body';
      }

      final data = jsonDecode(body) as Map<String, dynamic>;
      final tableau =
          data['currentTableau'] as Map<String, dynamic>? ?? const {};
      final glyphs = tableau['glyphs'] as List<dynamic>? ?? [];

      final result = _authGenerator.generate(
        glyphs,
        defaultValue: defaultValue,
      );

      if (!result.isAuthScreen) {
        return '# No Auth Screen Detected\n\n'
            'The current screen does not appear to be a login/auth '
            'screen. No text fields or login buttons were found.\n\n'
            'Navigate to your login screen first, then call this '
            'tool again.';
      }

      // Format output
      final buf = StringBuffer();
      buf.writeln('# Auto-Generated authStratagem');
      buf.writeln();
      buf.writeln(
        'Detected **${result.textFields.length}** text field(s) '
        'and **${result.loginButtons.length}** login button(s) on the '
        'current screen.',
      );
      buf.writeln();
      buf.writeln('## Detected Elements');
      buf.writeln();
      for (final f in result.textFields) {
        buf.writeln(
          '- \u270f\ufe0f Text field: **${f['l']}** '
          '(${f['wt']})',
        );
      }
      for (final b in result.loginButtons) {
        buf.writeln(
          '- \ud83d\udd18 Login button: **${b['l']}** '
          '(${b['wt']})',
        );
      }
      buf.writeln();
      buf.writeln('## authStratagem JSON');
      buf.writeln();
      buf.writeln('Add this to your Campaign JSON:');
      buf.writeln();
      buf.writeln('```json');
      buf.writeln(
        const JsonEncoder.withIndent(
          '  ',
        ).convert({'authStratagem': result.authStratagem}),
      );
      buf.writeln('```');
      buf.writeln();
      buf.writeln(
        '> **Note**: Replace `$defaultValue` with the '
        'actual login value for each field.',
      );

      return buf.toString();
    } on SocketException {
      return 'Cannot connect to Relay — is the app running '
          'with ColossusPlugin(enableRelay: true)?';
    } on TimeoutException {
      return 'Relay did not respond (timeout)';
    } finally {
      client.close();
    }
  }

  /// Auto-generate a complete Campaign JSON from the live app.
  ///
  /// Fetches the current Tableau from Relay, analyzes all interactive
  /// elements, and builds a ready-to-execute Campaign JSON with
  /// proper schema (int step IDs, startRoute, entries format).
  Future<String> _generateCampaign(Map<String, dynamic> args) async {
    final campaignName = args['name'] as String? ?? 'auto_campaign';
    final description =
        args['description'] as String? ?? 'Auto-generated from live screen';
    final defaultValue = args['defaultValue'] as String? ?? '<fill_in_value>';
    final includeAuth = args['includeAuth'] as bool? ?? true;

    final client = HttpClient();
    try {
      client.connectionTimeout = const Duration(seconds: 5);

      final request = await client.getUrl(_relayUri('/blueprint'));
      _relayHeaders.forEach(request.headers.set);

      final response = await request.close().timeout(
        const Duration(seconds: 5),
      );

      final body = await response.transform(utf8.decoder).join();

      if (response.statusCode != 200) {
        return 'Relay returned ${response.statusCode}: $body';
      }

      final data = jsonDecode(body) as Map<String, dynamic>;
      final tableau =
          data['currentTableau'] as Map<String, dynamic>? ?? const {};
      final glyphs = tableau['glyphs'] as List<dynamic>? ?? [];

      if (glyphs.isEmpty) {
        return '# No Glyphs Found\n\n'
            'The current screen has no widget tree data. '
            'Make sure the app is running and visible.';
      }

      // Check for auth screen
      Map<String, dynamic>? authStratagem;
      if (includeAuth) {
        final authResult = _authGenerator.generate(
          glyphs,
          defaultValue: defaultValue,
        );
        if (authResult.isAuthScreen) {
          authStratagem = authResult.authStratagem;
        }
      }

      // Collect interactive elements for stratagem entries
      final tappables = <Map<String, dynamic>>[];
      final textFields = <Map<String, dynamic>>[];
      final seenLabels = <String>{};

      for (final g in glyphs) {
        final glyph = g as Map<String, dynamic>;
        final isInteractive = glyph['ia'] == true;
        final label = (glyph['l'] as String? ?? '').trim();
        final interactionType = glyph['it'] as String? ?? '';
        final widgetType = glyph['wt'] as String? ?? '';

        // Skip non-interactive, empty, single-char, or duplicate labels
        if (!isInteractive || label.length < 2) continue;
        if (seenLabels.contains(label)) continue;
        seenLabels.add(label);

        if (interactionType == 'textInput' ||
            widgetType == 'TextField' ||
            widgetType == 'TextFormField') {
          textFields.add(glyph);
        } else if (interactionType == 'tap') {
          tappables.add(glyph);
        }
      }

      // Build entries — one stratagem per interactive element
      final entries = <Map<String, dynamic>>[];

      // Text field entries: enterText + verify
      for (final field in textFields) {
        final fieldLabel = field['l'] as String;
        entries.add({
          'stratagem': {
            'name': 'fill_${_slugify(fieldLabel)}',
            'description': 'Enter text in "$fieldLabel"',
            'startRoute': '/',
            'steps': [
              {
                'id': 1,
                'action': 'enterText',
                'target': {'label': fieldLabel},
                'value': defaultValue,
                'description': 'Type into "$fieldLabel"',
              },
            ],
          },
          'dependsOn': <String>[],
        });
      }

      // Tap entries: one stratagem per tappable
      for (final button in tappables) {
        final buttonLabel = button['l'] as String;
        entries.add({
          'stratagem': {
            'name': 'tap_${_slugify(buttonLabel)}',
            'description': 'Tap "$buttonLabel"',
            'startRoute': '/',
            'steps': [
              {
                'id': 1,
                'action': 'tap',
                'target': {'label': buttonLabel},
                'description': 'Tap "$buttonLabel"',
              },
            ],
          },
          'dependsOn': <String>[],
        });
      }

      if (entries.isEmpty) {
        return '# No Interactive Elements Found\n\n'
            'The current screen has no tappable buttons or '
            'text fields to generate tests for.\n\n'
            'Navigate to a screen with interactive elements '
            'and try again.';
      }

      // Build complete Campaign JSON
      final campaign = <String, dynamic>{
        r'$schema': 'titan://campaign/v1',
        'name': campaignName,
        'description': description,
        // ignore: use_null_aware_elements
        if (authStratagem != null) 'authStratagem': authStratagem,
        'entries': entries,
      };

      // Format output
      final buf = StringBuffer();
      buf.writeln('# Auto-Generated Campaign');
      buf.writeln();
      buf.writeln('**Name**: $campaignName');
      buf.writeln(
        '**Entries**: ${entries.length} '
        '(${textFields.length} text fields, '
        '${tappables.length} tap targets)',
      );
      if (authStratagem != null) {
        buf.writeln('**Auth**: Included (login screen detected)');
      }
      buf.writeln();

      buf.writeln('## Detected Elements');
      buf.writeln();
      for (final f in textFields) {
        buf.writeln('- \u270f\ufe0f Text: **${f['l']}** (${f['wt']})');
      }
      for (final b in tappables) {
        buf.writeln('- \ud83d\udd18 Tap: **${b['l']}** (${b['wt']})');
      }
      buf.writeln();

      buf.writeln('## Campaign JSON');
      buf.writeln();
      buf.writeln(
        'Pass this directly to `execute_campaign`, '
        'or modify entries as needed:',
      );
      buf.writeln();
      buf.writeln('```json');
      buf.writeln(const JsonEncoder.withIndent('  ').convert(campaign));
      buf.writeln('```');
      buf.writeln();
      buf.writeln(
        '> **Tip**: Modify the entries to match your '
        'desired test flow. You can reorder, remove, or add '
        'dependencies between entries.',
      );

      return buf.toString();
    } on SocketException {
      return 'Cannot connect to Relay — is the app running '
          'with ColossusPlugin(enableRelay: true)?';
    } on TimeoutException {
      return 'Relay did not respond (timeout)';
    } finally {
      client.close();
    }
  }

  // -----------------------------------------------------------------------
  // Screen Audit — automatic data-binding bug detection
  // -----------------------------------------------------------------------

  /// Instance of the screen auditor for snapshot comparison.
  static const _screenAuditor = ScreenAuditor();
  static const _scryEngine = Scry();

  /// Last observed [ScryGaze] for diff comparison.
  static ScryGaze? _lastGaze;

  /// Automatically detect data-binding bugs via a full
  /// sign-out → re-login cycle.
  ///
  /// 1. Fetches current screen (snapshot A)
  /// 2. Detects sign-out button & original displayed name
  /// 3. Signs out via a mini Campaign
  /// 4. Detects auth fields on login screen
  /// 5. Logs in with a unique probe value
  /// 6. Fetches screen again (snapshot B)
  /// 7. Runs [ScreenAuditor.compareScreens] to find anomalies
  /// 8. Optionally restores original state
  /// 9. Returns formatted audit report
  Future<String> _auditScreen(Map<String, dynamic> args) async {
    final testValue =
        args['testValue'] as String? ?? ScreenAuditor.generateProbeValue();
    final signOutLabelArg = args['signOutLabel'] as String?;
    final restore = args['restore'] as bool? ?? true;

    try {
      // Step 1: Fetch current screen (snapshot A)
      final glyphsBefore = await _fetchGlyphs();
      if (glyphsBefore == null) {
        return '# Audit Failed\n\n'
            'Could not fetch screen data from Relay. '
            'Is the app running with ColossusPlugin(enableRelay: true)?';
      }
      // Step 2: Detect sign-out button
      final signOutLabel =
          signOutLabelArg ??
          _screenAuditor.detectSignOutButtons(glyphsBefore).firstOrNull;

      if (signOutLabel == null) {
        return '# Audit Failed\n\n'
            'No sign-out button detected on the current screen. '
            'Navigate to a screen with a Sign Out / Log Out button, '
            'or specify the `signOutLabel` parameter.';
      }

      // Note: extract display labels before sign-out for comparison
      final labelsBefore = _screenAuditor.extractDisplayLabels(glyphsBefore);

      // Step 3: Sign out via mini Campaign.
      // Use waitForElementGone to ensure the sign-out navigation
      // completes before the campaign returns (more reliable than
      // a fixed delay, since it watches the actual widget tree).
      final signOutCampaign = {
        'name': '_audit_signout',
        'entries': [
          {
            'stratagem': {
              'name': '_signout',
              'startRoute': '/',
              'steps': [
                {
                  'id': 1,
                  'action': 'tap',
                  'target': {'label': signOutLabel},
                },
                {
                  'id': 2,
                  'action': 'waitForElementGone',
                  'target': {'label': signOutLabel},
                  'timeout': 5000,
                },
              ],
            },
          },
        ],
      };

      final signOutResult = await _executeRawCampaign(signOutCampaign);
      if (signOutResult == null || signOutResult['passRate'] != 1.0) {
        return '# Audit Failed\n\n'
            'Sign-out step failed. The button "$signOutLabel" '
            'could not be tapped successfully.\n\n'
            'Result: ${signOutResult ?? "no response"}';
      }

      // Step 4: Poll for login screen (Tableau may lag behind navigation)
      List<dynamic>? loginGlyphs;
      AuthStratagemResult? authResult;
      for (var attempt = 0; attempt < 10; attempt++) {
        await Future<void>.delayed(const Duration(milliseconds: 500));
        loginGlyphs = await _fetchGlyphs();
        if (loginGlyphs != null) {
          authResult = _authGenerator.generate(
            loginGlyphs,
            defaultValue: testValue,
          );
          if (authResult.isAuthScreen) {
            break;
          }
        }
      }

      if (loginGlyphs == null) {
        return '# Audit Failed\n\n'
            'Could not fetch login screen after sign-out.';
      }

      if (authResult == null || !authResult.isAuthScreen) {
        return '# Audit Failed\n\n'
            'After signing out, the screen does not appear to be '
            'a login screen (no text fields or login buttons found). '
            'The app may not have navigated to the login screen.';
      }

      // Step 5: Login with probe value via mini Campaign
      // Verify login success by waiting for the sign-out button
      // to reappear (it only exists on authenticated screens).
      final loginCampaign = {
        'name': '_audit_login',
        'authStratagem': authResult.authStratagem,
        'entries': [
          {
            'stratagem': {
              'name': '_post_login_check',
              'startRoute': '/',
              'steps': [
                {
                  'id': 1,
                  'action': 'waitForElement',
                  'target': {'label': signOutLabel},
                  'timeout': 5000,
                },
              ],
            },
          },
        ],
      };

      final loginResult = await _executeRawCampaign(loginCampaign);
      if (loginResult == null || loginResult['passRate'] != 1.0) {
        return '# Audit Failed\n\n'
            'Login step failed. Could not log in with probe value '
            '"$testValue".\n\n'
            'Result: ${loginResult ?? "no response"}';
      }

      // Step 6: Fetch post-login screen (snapshot B)
      // Brief settle delay to let the screen fully render
      await Future<void>.delayed(const Duration(milliseconds: 500));
      final glyphsAfter = await _fetchGlyphs();
      if (glyphsAfter == null) {
        return '# Audit Failed\n\n'
            'Could not fetch screen after re-login.';
      }

      // Step 7: Run the audit comparison
      final report = _screenAuditor.compareScreens(
        glyphsBefore: glyphsBefore,
        glyphsAfter: glyphsAfter,
        testInput: testValue,
      );

      // Step 8: Restore original state (if requested)
      String? restorationNote;
      if (restore) {
        // Try to find the original name from labels that disappeared
        // (the old name should be in labelsBefore but not labelsAfter)
        final disappeared = labelsBefore.difference(
          _screenAuditor.extractDisplayLabels(glyphsAfter),
        );

        // Pick the most name-like disappeared label as the original
        String? originalName;
        for (final label in disappeared) {
          // Use a simple heuristic: short, alphabetic label
          if (label.length >= 2 &&
              label.length <= 25 &&
              !label.contains('•') &&
              !label.contains(':')) {
            originalName = label;
            break;
          }
        }

        if (originalName != null) {
          // Sign out current probe user, then re-login with original name
          final signOutFirst = {
            'name': '_audit_restore_signout',
            'entries': [
              {
                'stratagem': {
                  'name': '_restore_signout',
                  'startRoute': '/',
                  'steps': [
                    {
                      'id': 1,
                      'action': 'tap',
                      'target': {'label': signOutLabel},
                    },
                    {
                      'id': 2,
                      'action': 'waitForElementGone',
                      'target': {'label': signOutLabel},
                      'timeout': 5000,
                    },
                  ],
                },
              },
            ],
          };
          await _executeRawCampaign(signOutFirst);

          // Wait for login screen, then build restore auth steps
          await Future<void>.delayed(const Duration(seconds: 1));

          // Build sequential step IDs for restore auth
          final restoreSteps = <Map<String, dynamic>>[];
          var restoreStepId = 1;
          for (final field in authResult.textFields) {
            restoreSteps.add({
              'id': restoreStepId++,
              'action': 'enterText',
              'target': {'label': field['l']},
              'value': originalName,
            });
          }
          for (final button in authResult.loginButtons) {
            restoreSteps.add({
              'id': restoreStepId++,
              'action': 'tap',
              'target': {'label': button['l']},
            });
          }

          final restoreCampaign = {
            'name': '_audit_restore_login',
            'authStratagem': {
              'name': '_restore_auth',
              'startRoute': '',
              'steps': restoreSteps,
            },
            'entries': [
              {
                'stratagem': {
                  'name': '_restore_verify',
                  'startRoute': '/',
                  'steps': [
                    {
                      'id': 1,
                      'action': 'waitForElement',
                      'target': {'label': signOutLabel},
                      'timeout': 5000,
                    },
                  ],
                },
              },
            ],
          };

          final restoreResult = await _executeRawCampaign(restoreCampaign);
          restorationNote = restoreResult?['passRate'] == 1.0
              ? 'Original state restored (logged back in as '
                    '"$originalName").'
              : 'Could not restore original state. Currently '
                    'logged in as "$testValue".';
        } else {
          restorationNote =
              'Could not determine original name for restoration. '
              'Currently logged in as "$testValue".';
        }
      }

      // Step 9: Format and return the report
      return _formatAuditReport(report, restorationNote);
    } on SocketException {
      return 'Cannot connect to Relay — is the app running '
          'with ColossusPlugin(enableRelay: true)?';
    } on TimeoutException {
      return 'Relay did not respond (timeout)';
    }
  }

  // -----------------------------------------------------------------------
  // Scry — Real-Time AI Agent Interface
  // -----------------------------------------------------------------------

  /// Observe the current screen state.
  Future<String> _scry() async {
    try {
      final blueprint = await _fetchBlueprintData();
      if (blueprint == null) {
        return '# Scry Failed\n\n'
            'Could not connect to Relay. '
            'Is the app running with ColossusPlugin(enableRelay: true)?';
      }

      final tableau =
          blueprint['currentTableau'] as Map<String, dynamic>? ?? const {};
      final glyphs = tableau['glyphs'] as List<dynamic>? ?? [];
      final route = tableau['route'] as String?;

      if (glyphs.isEmpty) {
        return '# Scry — Empty Screen\n\n'
            'The screen has no visible elements. '
            'The app may be loading or in a transition state.';
      }

      final gaze = _scryEngine.observe(glyphs, route: route);
      _lastGaze = gaze;
      return _scryEngine.formatGaze(gaze);
    } on SocketException {
      return '# Scry Failed\n\nCannot connect to Relay.';
    } on TimeoutException {
      return '# Scry Failed\n\nRelay did not respond (timeout).';
    }
  }

  /// Execute one or more actions on the live app.
  Future<String> _scryAct(Map<String, dynamic> args) async {
    final actionsList = args['actions'] as List<dynamic>?;

    // Multi-action mode
    if (actionsList != null && actionsList.isNotEmpty) {
      return _scryActMulti(actionsList);
    }

    // Single-action mode
    final action = args['action'] as String?;
    if (action == null || action.isEmpty) {
      return '# Scry Act Failed\n\n'
          'Missing required parameter: provide either `action` (single) '
          'or `actions` (array) parameter. '
          'Available actions: tap, enterText, clearText, scroll, back, '
          'longPress, doubleTap, swipe, navigate, waitForElement, '
          'waitForElementGone, pressKey, submitField, dismissKeyboard.';
    }

    var label = args['label'] as String?;
    final fieldId = args['fieldId'] as String?;
    final value = args['value'] as String?;
    final key = args['key'] as String?;

    if (label == null &&
        fieldId == null &&
        key == null &&
        action != 'back' &&
        action != 'navigate' &&
        action != 'dismissKeyboard' &&
        action != 'scroll') {
      return '# Scry Act Failed\n\n'
          'Missing target: provide `label`, `key`, or `fieldId` to identify '
          'the element to interact with. Use `scry` first to see '
          'available elements.';
    }

    try {
      // Resolve fieldId → label when only fieldId is provided.
      if (label == null && fieldId != null) {
        label = await _resolveFieldId(fieldId);
        if (label == null) {
          return '# Scry Act Failed\n\n'
              'Could not find a text field with fieldId "$fieldId" on the '
              'current screen. Use `scry` to see available fields and '
              'their labels.';
        }
      }

      // Build and execute the campaign
      final campaign = _scryEngine.buildActionCampaign(
        action: action,
        label: label,
        value: value,
        key: key,
      );

      final result = await _executeRawCampaign(campaign);

      // Settle delay for screen to update after navigation transitions.
      await Future<void>.delayed(const Duration(milliseconds: 1000));

      // Observe the new screen state
      final newGaze = await _observeCurrentScreen();
      _lastGaze = newGaze;

      return _scryEngine.formatActionResult(
        action: action,
        label: label,
        value: value,
        result: result,
        newGaze: newGaze,
      );
    } on SocketException {
      return '# Scry Act Failed\n\nCannot connect to Relay.';
    } on TimeoutException {
      return '# Scry Act Failed\n\nRelay did not respond (timeout).';
    }
  }

  /// Execute multiple actions in sequence on the live app.
  Future<String> _scryActMulti(List<dynamic> actionsList) async {
    try {
      // Validate and resolve each action
      final resolvedActions = <Map<String, dynamic>>[];
      List<dynamic>? cachedGlyphs;

      for (var i = 0; i < actionsList.length; i++) {
        final entry = actionsList[i] as Map<String, dynamic>;
        final action = entry['action'] as String?;
        if (action == null || action.isEmpty) {
          return '# Scry Act Failed\n\n'
              'Action ${i + 1} is missing the `action` field.';
        }

        var label = entry['label'] as String?;
        final fieldId = entry['fieldId'] as String?;
        final value = entry['value'] as String?;
        final key = entry['key'] as String?;

        // Resolve fieldId → label
        if (label == null && fieldId != null) {
          // Lazy-load glyphs once for all resolutions
          if (cachedGlyphs == null) {
            final blueprint = await _fetchBlueprintData();
            final tableau =
                blueprint?['currentTableau'] as Map<String, dynamic>? ??
                const {};
            cachedGlyphs = tableau['glyphs'] as List<dynamic>? ?? [];
          }
          label = _scryEngine.resolveFieldLabel(cachedGlyphs, fieldId);
          if (label == null) {
            return '# Scry Act Failed\n\n'
                'Action ${i + 1}: could not find a text field with '
                'fieldId "$fieldId". Use `scry` to see available fields.';
          }
        }

        // Validate target for actions that need one
        if (label == null &&
            key == null &&
            action != 'back' &&
            action != 'navigate' &&
            action != 'dismissKeyboard' &&
            action != 'scroll') {
          return '# Scry Act Failed\n\n'
              'Action ${i + 1} (`$action`): missing target. Provide '
              '`label`, `key`, or `fieldId`.';
        }

        resolvedActions.add({
          'action': action,
          // ignore: use_null_aware_elements
          if (label != null) 'label': label,
          // ignore: use_null_aware_elements
          if (key != null) 'key': key,
          // ignore: use_null_aware_elements
          if (value != null) 'value': value,
        });
      }

      // Build and execute the combined campaign
      final campaign = _scryEngine.buildMultiActionCampaign(resolvedActions);
      final result = await _executeRawCampaign(campaign);

      // Settle delay
      await Future<void>.delayed(const Duration(milliseconds: 1000));

      // Observe the new screen state
      final newGaze = await _observeCurrentScreen();
      _lastGaze = newGaze;

      return _scryEngine.formatMultiActionResult(
        actions: resolvedActions,
        result: result,
        newGaze: newGaze,
      );
    } on SocketException {
      return '# Scry Act Failed\n\nCannot connect to Relay.';
    } on TimeoutException {
      return '# Scry Act Failed\n\nRelay did not respond (timeout).';
    }
  }

  /// Compare the current screen state against the last observation.
  Future<String> _scryDiff() async {
    final previousGaze = _lastGaze;
    if (previousGaze == null) {
      return '# Scry Diff Failed\n\n'
          'No previous observation to compare against. '
          'Call `scry` at least once before using `scry_diff`.';
    }

    try {
      final currentGaze = await _observeCurrentScreen();
      final diff = _scryEngine.diff(previousGaze, currentGaze);

      // Update cached gaze to current
      _lastGaze = currentGaze;

      final buf = StringBuffer();
      buf.write(diff.format());
      buf.writeln();
      buf.writeln('---');
      buf.writeln();
      buf.write(_scryEngine.formatGaze(currentGaze));
      return buf.toString();
    } on SocketException {
      return '# Scry Diff Failed\n\nCannot connect to Relay.';
    } on TimeoutException {
      return '# Scry Diff Failed\n\nRelay did not respond (timeout).';
    }
  }

  /// Resolve a fieldId to its display label from current screen glyphs.
  Future<String?> _resolveFieldId(String fieldId) async {
    final blueprint = await _fetchBlueprintData();
    final tableau =
        blueprint?['currentTableau'] as Map<String, dynamic>? ?? const {};
    final glyphs = tableau['glyphs'] as List<dynamic>? ?? [];
    return _scryEngine.resolveFieldLabel(glyphs, fieldId);
  }

  /// Observe the current screen and return a [ScryGaze].
  Future<ScryGaze> _observeCurrentScreen() async {
    final blueprint = await _fetchBlueprintData();
    final tableau =
        blueprint?['currentTableau'] as Map<String, dynamic>? ?? const {};
    final glyphs = tableau['glyphs'] as List<dynamic>? ?? [];
    final route = tableau['route'] as String?;
    return _scryEngine.observe(glyphs, route: route);
  }

  // -----------------------------------------------------------------------
  // Relay helpers
  // -----------------------------------------------------------------------

  /// Fetch the full blueprint data from Relay (includes tableau + route).
  Future<Map<String, dynamic>?> _fetchBlueprintData() async {
    final client = HttpClient();
    try {
      client.connectionTimeout = const Duration(seconds: 5);

      final request = await client.getUrl(_relayUri('/blueprint'));
      _relayHeaders.forEach(request.headers.set);

      final response = await request.close().timeout(
        const Duration(seconds: 5),
      );

      if (response.statusCode != 200) {
        await response.drain<void>();
        return null;
      }

      final body = await response.transform(utf8.decoder).join();
      return jsonDecode(body) as Map<String, dynamic>;
    } on SocketException {
      return null;
    } on TimeoutException {
      return null;
    } finally {
      client.close();
    }
  }

  /// Fetch current screen glyphs from Relay.
  Future<List<dynamic>?> _fetchGlyphs() async {
    final client = HttpClient();
    try {
      client.connectionTimeout = const Duration(seconds: 5);

      final request = await client.getUrl(_relayUri('/blueprint'));
      _relayHeaders.forEach(request.headers.set);

      final response = await request.close().timeout(
        const Duration(seconds: 5),
      );

      if (response.statusCode != 200) {
        await response.drain<void>();
        return null;
      }

      final body = await response.transform(utf8.decoder).join();
      final data = jsonDecode(body) as Map<String, dynamic>;
      final tableau =
          data['currentTableau'] as Map<String, dynamic>? ?? const {};
      return tableau['glyphs'] as List<dynamic>? ?? [];
    } on SocketException {
      return null;
    } on TimeoutException {
      return null;
    } finally {
      client.close();
    }
  }

  /// Execute a campaign via Relay and return the parsed result.
  Future<Map<String, dynamic>?> _executeRawCampaign(
    Map<String, dynamic> campaign,
  ) async {
    final client = HttpClient();
    try {
      client.connectionTimeout = const Duration(seconds: 10);

      final request = await client.postUrl(_relayUri('/campaign'));
      _relayHeaders.forEach(request.headers.set);
      request.add(utf8.encode(jsonEncode(campaign)));

      final response = await request.close().timeout(
        const Duration(minutes: 5),
      );

      final body = await response.transform(utf8.decoder).join();

      if (response.statusCode == 200) {
        return jsonDecode(body) as Map<String, dynamic>;
      }
      return null;
    } on SocketException {
      return null;
    } on TimeoutException {
      return null;
    } finally {
      client.close();
    }
  }

  /// Format an [AuditReport] as Markdown for AI consumption.
  String _formatAuditReport(AuditReport report, String? restorationNote) {
    final buf = StringBuffer();

    buf.writeln('# Screen Audit Report');
    buf.writeln();

    if (report.hasBugs) {
      buf.writeln(
        '\u274c **BUGS DETECTED** — '
        '${report.bugs.length} data-binding issue(s) found',
      );
    } else {
      buf.writeln('\u2705 **NO BUGS DETECTED** — screen audit passed');
    }
    buf.writeln();

    buf.writeln('**Probe Value**: `${report.testInput}`');
    buf.writeln('**Labels Before**: ${report.labelsBefore.length}');
    buf.writeln('**Labels After**: ${report.labelsAfter.length}');
    buf.writeln(
      '**Findings**: ${report.bugs.length} bugs, '
      '${report.warnings.length} warnings, '
      '${report.infos.length} info',
    );
    buf.writeln();

    if (report.bugs.isNotEmpty) {
      buf.writeln('## \u274c Bugs');
      buf.writeln();
      for (final bug in report.bugs) {
        buf.writeln('- **${bug.category}**: ${bug.message}');
        if (bug.expected != null) {
          buf.writeln('  - Expected: `${bug.expected}`');
        }
        if (bug.actual != null) {
          buf.writeln('  - Actual: `${bug.actual}`');
        }
      }
      buf.writeln();
    }

    if (report.warnings.isNotEmpty) {
      buf.writeln('## \u26a0\ufe0f Warnings');
      buf.writeln();
      for (final w in report.warnings) {
        buf.writeln('- **${w.category}**: ${w.message}');
      }
      buf.writeln();
    }

    if (report.infos.isNotEmpty) {
      buf.writeln('## \u2139\ufe0f Info');
      buf.writeln();
      for (final info in report.infos) {
        buf.writeln('- **${info.category}**: ${info.message}');
      }
      buf.writeln();
    }

    if (report.disappeared.isNotEmpty) {
      buf.writeln('## Labels That Disappeared');
      buf.writeln();
      for (final label in report.disappeared.take(10)) {
        buf.writeln('- `$label`');
      }
      if (report.disappeared.length > 10) {
        buf.writeln('- (+${report.disappeared.length - 10} more)');
      }
      buf.writeln();
    }

    if (restorationNote != null) {
      buf.writeln('---');
      buf.writeln();
      buf.writeln('**Restoration**: $restorationNote');
    }

    return buf.toString();
  }

  /// Convert a label to a URL-safe slug for stratagem names.
  static String _slugify(String label) {
    return label
        .toLowerCase()
        .replaceAll(RegExp(r'[^a-z0-9]+'), '_')
        .replaceAll(RegExp(r'^_+|_+$'), '');
  }

  /// Get the live Terrain from the running app (not from static file).
  Future<String> _relayTerrain() async {
    final client = HttpClient();
    try {
      client.connectionTimeout = const Duration(seconds: 5);

      final request = await client.getUrl(_relayUri('/terrain'));
      _relayHeaders.forEach(request.headers.set);

      final response = await request.close().timeout(
        const Duration(seconds: 5),
      );

      final body = await response.transform(utf8.decoder).join();

      if (response.statusCode == 200) {
        try {
          final data = jsonDecode(body) as Map<String, dynamic>;
          final buf = StringBuffer();
          buf.writeln('# Live Terrain (from running app)');
          buf.writeln();

          final outposts = data['outposts'] as List<dynamic>? ?? [];
          final marches = data['marches'] as List<dynamic>? ?? [];
          buf.writeln('**Screens**: ${outposts.length}');
          buf.writeln('**Transitions**: ${marches.length}');
          buf.writeln();

          if (outposts.isNotEmpty) {
            buf.writeln('## Screens');
            for (final o in outposts) {
              final map = o as Map<String, dynamic>;
              buf.writeln(
                '- `${map['route']}` '
                '(${map['visitCount'] ?? 0} visits)',
              );
            }
            buf.writeln();
          }

          if (marches.isNotEmpty) {
            buf.writeln('## Transitions');
            for (final m in marches) {
              final map = m as Map<String, dynamic>;
              buf.writeln(
                '- `${map['from']}` \u2192 `${map['to']}` '
                '(${map['count'] ?? 0}x, '
                '${((map['reliability'] ?? 1.0) * 100).toStringAsFixed(0)}%)',
              );
            }
          }

          return buf.toString();
        } catch (_) {
          return body;
        }
      } else {
        return 'Relay returned ${response.statusCode}: $body';
      }
    } on SocketException {
      return 'Cannot connect to Relay — is the app running?';
    } on TimeoutException {
      return 'Relay did not respond (timeout)';
    } finally {
      client.close();
    }
  }

  // -----------------------------------------------------------------------
  // Blueprint loading with caching
  // -----------------------------------------------------------------------

  Future<Map<String, dynamic>?> _loadBlueprint() async {
    final file = File(_blueprintPath);
    if (!file.existsSync()) return null;

    final modified = file.lastModifiedSync();
    if (_cachedBlueprint != null && _lastModified == modified) {
      return _cachedBlueprint;
    }

    try {
      final content = await file.readAsString();
      _cachedBlueprint = jsonDecode(content) as Map<String, dynamic>;
      _lastModified = modified;
      return _cachedBlueprint;
    } catch (_) {
      return null;
    }
  }
}
